@namespace sv_5ff275eedc5248608b7b5334b05297e4.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionSelected.InvokeAsync(section)">
                    <span class="section-icon">@GetIcon(section)</span>
                    @section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionSelected { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_5ff275eedc5248608b7b5334b05297e4.Components.Pages.Settings

<div class="card settings-section">
    <div class="card-body">
        <h4 class="card-title mb-4">Profile Settings</h4>

        @if (StatusMessage is not null)
        {
            <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @StatusMessage
                <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label fw-semibold">Display Name</label>
                    <input type="text" class="form-control" @bind="displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Email</label>
                    <input type="email" class="form-control" @bind="email" />
                </div>

                <div class="mb-3">
                    <label class="form-label fw-semibold">Bio</label>
                    <textarea class="form-control" rows="4" @bind="bio"></textarea>
                </div>
            </div>

            <div class="col-md-4 text-center">
                <div class="avatar-preview mb-3">
                    <img src="@avatarUrl" alt="Avatar" class="rounded-circle" width="96" height="96" />
                </div>
                <div class="mb-3">
                    <label class="form-label fw-semibold">Avatar URL</label>
                    <input type="url" class="form-control form-control-sm" @bind="avatarUrl" />
                </div>
            </div>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
                @if (isSaving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@isSaving">
                Discard Changes
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter] public EventCallback<UserProfile> OnSave { get; set; }

    private string displayName = "";
    private string email = "";
    private string avatarUrl = "";
    private string bio = "";
    private bool isSaving;
    private string? StatusMessage;
    private bool IsError;

    protected override void OnParametersSet()
    {
        if (!isSaving)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        displayName = Profile.DisplayName;
        email = Profile.Email;
        avatarUrl = Profile.AvatarUrl;
        bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        IsError = false;
        try
        {
            var updated = new UserProfile(displayName, email, avatarUrl, bio);
            await OnSave.InvokeAsync(updated);
            StatusMessage = "Profile saved successfully!";
        }
        catch
        {
            StatusMessage = "Failed to save profile.";
            IsError = true;
        }
        finally
        {
            isSaving = false;
        }
    }

    private void Discard()
    {
        LoadFromProfile();
        StatusMessage = null;
    }
}

@namespace sv_5ff275eedc5248608b7b5334b05297e4.Components.Pages.Settings

<div class="card settings-section">
    <div class="card-body">
        <h4 class="card-title mb-4">Notification Preferences</h4>

        @if (StatusMessage is not null)
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @StatusMessage
                <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
            </div>
        }

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">General</h6>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif"
                       checked="@emailNotifications" @onchange="e => emailNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif"
                       checked="@pushNotifications" @onchange="e => pushNotifications = (bool)e.Value!" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="weeklyDigest"
                       checked="@weeklyDigest" @onchange="e => weeklyDigest = (bool)e.Value!" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h6 class="fw-semibold mb-3">Muted Channels</h6>
            @if (allChannels.Count > 0)
            {
                @foreach (var channel in allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                               checked="@mutedChannels.Contains(channel)"
                               @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                        <label class="form-check-label" for="@($"ch-{channel}")">
                            <span class="badge bg-secondary me-1">#</span> @channel
                        </label>
                    </div>
                }
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
            @if (isSaving)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Save Preferences
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private List<string> mutedChannels = [];
    private List<string> allChannels = [];
    private bool isSaving;
    private string? StatusMessage;

    protected override void OnParametersSet()
    {
        if (!isSaving)
        {
            emailNotifications = Prefs.EmailNotifications;
            pushNotifications = Prefs.PushNotifications;
            weeklyDigest = Prefs.WeeklyDigest;
            allChannels = [.. Prefs.MutedChannels];
            mutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted && !mutedChannels.Contains(channel))
            mutedChannels.Add(channel);
        else if (!isMuted)
            mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        try
        {
            var updated = new NotificationPrefs(emailNotifications, pushNotifications, weeklyDigest, [.. mutedChannels]);
            await OnSave.InvokeAsync(updated);
            StatusMessage = "Preferences saved successfully!";
        }
        finally
        {
            isSaving = false;
        }
    }
}

@namespace sv_5ff275eedc5248608b7b5334b05297e4.Components.Pages.Settings

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="() => isExpanded = !isExpanded">
        <h6 class="mb-0">Change Password</h6>
        <span class="expand-icon">@(isExpanded ? "▲" : "▼")</span>
    </div>
    @if (isExpanded)
    {
        <div class="card-body">
            @if (StatusMessage is not null)
            {
                <div class="alert @(IsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @StatusMessage
                    <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>
            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>
            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@isUpdating">
                @if (isUpdating)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool isExpanded;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";
    private bool isUpdating;
    private string? StatusMessage;
    private bool IsError;

    private async Task UpdatePasswordAsync()
    {
        StatusMessage = null;
        IsError = false;

        if (string.IsNullOrWhiteSpace(currentPassword) ||
            string.IsNullOrWhiteSpace(newPassword))
        {
            StatusMessage = "Please fill in all password fields.";
            IsError = true;
            return;
        }

        if (newPassword != confirmPassword)
        {
            StatusMessage = "New password and confirmation do not match.";
            IsError = true;
            return;
        }

        isUpdating = true;
        try
        {
            await OnChangePassword.InvokeAsync((currentPassword, newPassword));
            StatusMessage = "Password updated successfully!";
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
        }
        catch
        {
            StatusMessage = "Failed to update password.";
            IsError = true;
        }
        finally
        {
            isUpdating = false;
        }
    }
}

@namespace sv_5ff275eedc5248608b7b5334b05297e4.Components.Pages.Settings

@if (IsVisible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered" role="document">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@Session?.Device</strong> from <strong>@Session?.Location</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button class="btn btn-secondary" @onclick="Cancel">Cancel</button>
                    <button class="btn btn-danger" @onclick="Confirm">Revoke Session</button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public bool IsVisible { get; set; }
    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private async Task Confirm() => await OnConfirm.InvokeAsync();
    private async Task Cancel() => await OnCancel.InvokeAsync();
}

@namespace sv_5ff275eedc5248608b7b5334b05297e4.Components.Pages.Settings

<div class="card settings-section">
    <div class="card-body">
        <h4 class="card-title mb-4">Security Settings</h4>

        <ChangePasswordPanel OnChangePassword="OnChangePassword" />

        <div class="card mb-3">
            <div class="card-body">
                <div class="d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="mb-1">Two-Factor Authentication</h6>
                        <span class="badge @(Security.TwoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(Security.TwoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox"
                               checked="@twoFactorEnabled"
                               @onchange="Toggle2FA" />
                    </div>
                </div>
                @if (Security.LastPasswordChange.HasValue)
                {
                    <p class="text-muted small mt-2 mb-0">
                        Last password change: @Security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                    </p>
                }
            </div>
        </div>

        <div class="card">
            <div class="card-body">
                <h6 class="mb-3">Active Sessions</h6>
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in Security.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td>
                                        @if (session.Id != CurrentSessionId)
                                        {
                                            <button class="btn btn-sm btn-outline-danger"
                                                    @onclick="() => PromptRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                        else
                                        {
                                            <span class="badge bg-info">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    </div>
</div>

<RevokeSessionDialog IsVisible="showRevokeDialog"
                     Session="sessionToRevoke"
                     OnConfirm="ConfirmRevoke"
                     OnCancel="CancelRevoke" />

@code {
    [Parameter, EditorRequired] public SecuritySettings Security { get; set; } = default!;
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }
    [Parameter] public EventCallback<bool> OnToggle2FA { get; set; }

    private string CurrentSessionId => Security.Sessions.FirstOrDefault()?.Id ?? "";

    private bool twoFactorEnabled;
    private bool showRevokeDialog;
    private ActiveSession? sessionToRevoke;

    protected override void OnParametersSet()
    {
        twoFactorEnabled = Security.TwoFactorEnabled;
    }

    private async Task Toggle2FA(ChangeEventArgs e)
    {
        twoFactorEnabled = (bool)e.Value!;
        await OnToggle2FA.InvokeAsync(twoFactorEnabled);
    }

    private void PromptRevoke(ActiveSession session)
    {
        sessionToRevoke = session;
        showRevokeDialog = true;
    }

    private async Task ConfirmRevoke()
    {
        if (sessionToRevoke is not null)
        {
            await OnRevokeSession.InvokeAsync(sessionToRevoke.Id);
        }
        showRevokeDialog = false;
        sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        showRevokeDialog = false;
        sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

