<div class="card settings-section">
    <div class="card-body">
        <h4 class="card-title mb-4">Appearance Settings</h4>

        @if (StatusMessage is not null)
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @StatusMessage
                <button type="button" class="btn-close" @onclick="() => StatusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-6">
                <div class="mb-4">
                    <h6 class="fw-semibold mb-3">Theme</h6>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(selectedTheme == theme)"
                                   @onchange="() => selectedTheme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6 class="fw-semibold mb-3">Font Size</h6>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"font-{size}")" value="@size"
                                   checked="@(selectedFontSize == size)"
                                   @onchange="() => selectedFontSize = size" />
                            <label class="form-check-label" for="@($"font-{size}")">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h6 class="fw-semibold mb-3">Language</h6>
                    <select class="form-select" @bind="selectedLanguage">
                        @foreach (var lang in Languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode"
                               checked="@compactMode" @onchange="e => compactMode = (bool)e.Value!" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@isSaving">
                    @if (isSaving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>
            </div>

            <div class="col-md-6">
                <h6 class="fw-semibold mb-3">Preview</h6>
                <div class="appearance-preview @PreviewThemeClass" style="@PreviewStyle">
                    <div class="preview-header">
                        <strong>Sample Header</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is a preview of your selected appearance settings.</p>
                        <button class="btn btn-sm @PreviewButtonClass">Sample Button</button>
                    </div>
                    @if (compactMode)
                    {
                        <div class="preview-compact-note">
                            <small>Compact mode: reduced spacing</small>
                        </div>
                    }
                </div>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Settings { get; set; } = default!;
    [Parameter] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string selectedTheme = "Light";
    private string selectedFontSize = "Medium";
    private string selectedLanguage = "English";
    private bool compactMode;
    private bool isSaving;
    private string? StatusMessage;

    private static readonly string[] Languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese"];

    protected override void OnParametersSet()
    {
        if (!isSaving)
        {
            selectedTheme = Settings.Theme;
            selectedFontSize = Settings.FontSize;
            selectedLanguage = Settings.Language;
            compactMode = Settings.CompactMode;
        }
    }

    private string PreviewThemeClass => selectedTheme switch
    {
        "Dark" => "preview-dark",
        "System" => "preview-system",
        _ => "preview-light"
    };

    private string PreviewButtonClass => selectedTheme == "Dark" ? "btn-light" : "btn-primary";

    private string PreviewStyle
    {
        get
        {
            var fontSize = selectedFontSize switch
            {
                "Small" => "0.85rem",
                "Large" => "1.15rem",
                _ => "1rem"
            };
            var padding = compactMode ? "0.5rem" : "1rem";
            return $"font-size: {fontSize}; --preview-padding: {padding};";
        }
    }

    private async Task SaveAsync()
    {
        isSaving = true;
        try
        {
            var updated = new AppearanceSettings(selectedTheme, selectedFontSize, selectedLanguage, compactMode);
            await OnSave.InvokeAsync(updated);
            StatusMessage = "Appearance saved successfully!";
        }
        finally
        {
            isSaving = false;
        }
    }
}

