@page "/settings"
@using sv_5ff275eedc5248608b7b5334b05297e4.Components.Pages.Settings
@using sv_5ff275eedc5248608b7b5334b05297e4.Services
@rendermode InteractiveServer
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

@if (isLoading)
{
    <div class="d-flex justify-content-center align-items-center" style="min-height: 400px;">
        <div class="spinner-border text-primary" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="settings-dashboard">
        <SettingsSidebar ActiveSection="@activeSection" OnSectionSelected="s => activeSection = s" />

        <div class="settings-content">
            @switch (activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="profile!" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="notificationPrefs!" OnSave="SaveNotificationsAsync" />
                    break;
                case "Security":
                    <SecuritySection Security="security!"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnRevokeSession="RevokeSessionAsync"
                                     OnToggle2FA="Toggle2FAAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Settings="appearance!" OnSave="SaveAppearanceAsync" />
                    break;
            }
        </div>
    </div>
}

@code {
    private string activeSection = "Profile";
    private bool isLoading = true;

    private UserProfile? profile;
    private NotificationPrefs? notificationPrefs;
    private SecuritySettings? security;
    private AppearanceSettings? appearance;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllAsync();
        isLoading = false;
    }

    private async Task LoadAllAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifsTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifsTask, securityTask, appearanceTask);

        profile = profileTask.Result;
        notificationPrefs = notifsTask.Result;
        security = securityTask.Result;
        appearance = appearanceTask.Result;
    }

    private async Task SaveProfileAsync(UserProfile updated)
    {
        await SettingsService.SaveProfileAsync(updated);
        profile = updated;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs updated)
    {
        await SettingsService.SaveNotificationPrefsAsync(updated);
        notificationPrefs = updated;
    }

    private async Task ChangePasswordAsync((string Current, string New) passwords)
    {
        await SettingsService.ChangePasswordAsync(passwords.Current, passwords.New);
        security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        security = await SettingsService.GetSecuritySettingsAsync();
    }

    private Task Toggle2FAAsync(bool enabled)
    {
        // 2FA toggle would call a real service; for now we just update local state
        if (security is not null)
        {
            security = security with { TwoFactorEnabled = enabled };
        }
        return Task.CompletedTask;
    }
}

.settings-dashboard {
    display: flex;
    gap: 1.5rem;
    min-height: 500px;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

::deep .settings-sidebar {
    width: 220px;
    flex-shrink: 0;
}

::deep .sidebar-title {
    padding: 0.75rem 1rem;
    margin-bottom: 0;
    color: #6c757d;
    font-size: 0.75rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
}

::deep .settings-sidebar .nav-link {
    color: #495057;
    border: none;
    background: none;
    width: 100%;
    text-align: left;
    padding: 0.6rem 1rem;
    border-radius: 0.375rem;
    display: flex;
    align-items: center;
    gap: 0.5rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: #f8f9fa;
}

::deep .settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
}

::deep .settings-section {
    border: 1px solid #dee2e6;
}

::deep .avatar-preview {
    border: 2px dashed #dee2e6;
    border-radius: 50%;
    width: 100px;
    height: 100px;
    margin: 0 auto;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
}

::deep .expand-icon {
    font-size: 0.75rem;
    color: #6c757d;
}

::deep .appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s;
}

::deep .preview-header {
    padding: var(--preview-padding, 1rem);
    border-bottom: 1px solid #dee2e6;
}

::deep .preview-body {
    padding: var(--preview-padding, 1rem);
}

::deep .preview-compact-note {
    padding: 0.25rem var(--preview-padding, 1rem);
    border-top: 1px solid #dee2e6;
}

::deep .preview-light {
    background-color: #ffffff;
    color: #212529;
}

::deep .preview-dark {
    background-color: #212529;
    color: #f8f9fa;
    border-color: #495057;
}

::deep .preview-dark .preview-header {
    border-color: #495057;
}

::deep .preview-dark .preview-compact-note {
    border-color: #495057;
}

::deep .preview-system {
    background: linear-gradient(135deg, #ffffff 50%, #212529 50%);
    color: #212529;
}

